tring // \"oauth\", \"credentials\"\n  provider          String // \"google\", \"apple\", \"credentials\"\n  providerAccountId String\n  refresh_token     String? @db.Text\n  access_token      String? @db.Text\n  expires_at        Int?\n  token_type        String?\n  scope             String?\n  id_token          String? @db.Text\n  session_state     String?\n\n  user User @relation(fields: [userId], references: [id], onDelete: Cascade)\n\n  @@unique([provider, providerAccountId])\n  @@index([userId])\n  @@map(\"accounts\")\n}\n\nmodel Session {\n  id           String   @id @default(cuid())\n  sessionToken String   @unique\n  userId       String\n  expires      DateTime\n\n  // Security tracking\n  ipAddress String?\n  userAgent String?\n  country   String? // Derived from IP for fraud detection\n  city      String?\n  deviceId  String? // Device fingerprint\n\n  createdAt  DateTime @default(now())\n  lastUsedAt DateTime @default(now())\n\n  user User @relation(fields: [userId], references: [id], onDelete: Cascade)\n\n  @@index([userId])\n  @@index([expires])\n  @@index([sessionToken])\n  @@map(\"sessions\")\n}\n\nmodel VerificationToken {\n  identifier String // email or phone\n  token      String   @unique\n  type       String // \"email_verification\", \"phone_verification\", \"password_reset\", \"2fa_setup\"\n  expires    DateTime\n  attempts   Int      @default(0)\n  createdAt  DateTime @default(now())\n\n  @@unique([identifier, token, type])\n  @@index([expires])\n  @@map(\"verification_tokens\")\n}\n\n// ============================================\n// WALLET & TRANSACTIONS\n// ============================================\n\nmodel Wallet {\n  id     String @id @default(cuid())\n  userId String @unique\n  user   User   @relation(fields: [userId], references: [id], onDelete: Cascade)\n\n  // Balances\n  balance       Decimal @default(0) @db.Decimal(15, 2)\n  totalDeposits Decimal @default(0) @db.Decimal(15, 2)\n  totalSpent    Decimal @default(0) @db.Decimal(15